// Feature Engineering Data Analysis Node
// This code analyzes CSV data and prepares context for LLM

const csvData = $input.all()[0].json.data;

// Helper function to detect column types
function analyzeColumn(values) {
  const nonEmpty = values.filter(v => v !== null && v !== undefined && v !== '');

  if (nonEmpty.length === 0) return { type: 'empty', stats: {} };

  // Try to convert to numbers
  const numbers = nonEmpty.map(v => {
    const num = parseFloat(v);
    return isNaN(num) ? null : num;
  }).filter(n => n !== null);

  if (numbers.length / nonEmpty.length > 0.8) {
    // Mostly numeric
    numbers.sort((a, b) => a - b);
    return {
      type: 'numeric',
      stats: {
        count: numbers.length,
        min: numbers[0],
        max: numbers[numbers.length - 1],
        mean: numbers.reduce((a, b) => a + b) / numbers.length,
        median: numbers[Math.floor(numbers.length / 2)],
        missing: values.length - nonEmpty.length,
        unique_values: new Set(numbers).size
      }
    };
  } else {
    // Categorical/text
    const uniqueValues = new Set(nonEmpty);
    return {
      type: 'categorical',
      stats: {
        count: nonEmpty.length,
        unique_values: uniqueValues.size,
        missing: values.length - nonEmpty.length,
        most_common: [...uniqueValues].slice(0, 5),
        cardinality: uniqueValues.size / nonEmpty.length
      }
    };
  }
}

// Helper function to detect potential datetime columns
function isDateColumn(columnName, values) {
  const dateWords = ['date', 'time', 'created', 'updated', 'year', 'month', 'day'];
  const nameHasDate = dateWords.some(word => columnName.toLowerCase().includes(word));

  if (nameHasDate) return true;

  // Check if values look like dates
  const sample = values.filter(v => v).slice(0, 10);
  const datePattern = /\d{4}-\d{2}-\d{2}|\d{2}\/\d{2}\/\d{4}|\d{4}\/\d{2}\/\d{2}/;
  const dateMatches = sample.filter(v => datePattern.test(v)).length;

  return dateMatches / sample.length > 0.5;
}

try {
  // Parse CSV data
  const lines = csvData.trim().split('\n');
  const headers = lines[0].split(',').map(h => h.replace(/"/g, '').trim());

  const rows = lines.slice(1).map(line => {
    // Simple CSV parsing - handle quoted fields
    const values = [];
    let current = '';
    let inQuotes = false;

    for (let i = 0; i < line.length; i++) {
      const char = line[i];
      if (char === '"') {
        inQuotes = !inQuotes;
      } else if (char === ',' && !inQuotes) {
        values.push(current.trim());
        current = '';
      } else {
        current += char;
      }
    }
    values.push(current.trim()); // Add the last value

    return values;
  });

  // Analyze each column
  const columnAnalysis = {};
  const numericColumns = [];
  const categoricalColumns = [];
  const dateColumns = [];

  headers.forEach((header, index) => {
    const values = rows.map(row => row[index]);
    const analysis = analyzeColumn(values);

    columnAnalysis[header] = analysis;

    if (analysis.type === 'numeric') {
      numericColumns.push(header);
    } else if (analysis.type === 'categorical') {
      categoricalColumns.push(header);
    }

    if (isDateColumn(header, values)) {
      dateColumns.push(header);
    }
  });

  // Calculate potential correlations (for numeric columns)
  const correlationCandidates = [];
  for (let i = 0; i < numericColumns.length; i++) {
    for (let j = i + 1; j < numericColumns.length; j++) {
      correlationCandidates.push([numericColumns[i], numericColumns[j]]);
    }
  }

  // Identify high-cardinality categorical columns (good for target encoding)
  const highCardinalityColumns = categoricalColumns.filter(col => {
    const stats = columnAnalysis[col].stats;
    return stats.unique_values > 10 && stats.cardinality < 0.8;
  });

  // Identify potential ratio candidates
  const ratioCandidates = [];
  numericColumns.forEach(num1 => {
    numericColumns.forEach(num2 => {
      if (num1 !== num2) {
        const col1Stats = columnAnalysis[num1].stats;
        const col2Stats = columnAnalysis[num2].stats;

        // Suggest ratios where denominator is generally non-zero
        if (col2Stats && col2Stats.min > 0 || (col2Stats && Math.abs(col2Stats.min) < col2Stats.max * 0.1)) {
          ratioCandidates.push([num1, num2]);
        }
      }
    });
  });

  // Prepare structured output for LLM
  const analysisResult = {
    dataset_summary: {
      total_rows: rows.length,
      total_columns: headers.length,
      numeric_columns: numericColumns.length,
      categorical_columns: categoricalColumns.length,
      date_columns: dateColumns.length
    },
    column_details: columnAnalysis,
    {{ RESOURCE_ID }}: {
      numeric_columns: numericColumns,
      categorical_columns: categoricalColumns,
      date_columns: dateColumns,
      {{ RESOURCE_ID }}: highCardinalityColumns,
      correlation_candidates: correlationCandidates.slice(0, 10), // Limit to top 10
      ratio_candidates: ratioCandidates.slice(0, 15), // Limit to top 15
      column_names: headers
    },
    data_quality: {
      columns_with_missing: Object.keys(columnAnalysis).filter(col => 
        columnAnalysis[col].stats.missing > 0
      ),
      total_missing_values: Object.values(columnAnalysis).reduce((sum, col) => 
        sum + (col.stats.missing || 0), 0
      )
    }
  };

  return [{ json: analysisResult }];

} catch (error) {
  console.error('Error analyzing data:', error);
  return [{ 
    json: { 
      error: 'Failed to analyze data: ' + error.message,
      raw_data_preview: csvData ? csvData.substring(0, 500) : 'No CSV data found'
    } 
  }];
}

